// ================================================================
// Deep Research Engine v2
// Multi-phase parallel research with entity extraction,
// cross-referencing, 5 depth levels, and compare mode.
// Ported from OpenWebUI Deep Research v2 + n8n parallelism.
// ================================================================

const SEARXNG_URL = 'http://192.168.1.141:8888';
const OLLAMA_URL = 'http://192.168.1.110:11434';
const RESEARCH_MODEL = 'qwen3.5:27b';
const MAX_PAGE_CHARS = 6000;

const input = $input.item.json.body || $input.item.json;
const topic = input.topic || input.query || '';
const depth = Math.max(1, Math.min(5, parseInt(input.depth) || 3));
const focus = input.focus || '';
const mode = input.mode || 'research'; // 'research' | 'compare' | 'quick'
const topicB = input.topic_b || ''; // For compare mode

const timeline = [];
const allFindings = [];
const fullPages = [];
const allSources = [];
const searched = new Set();
const fetched = new Set();
let keyEntities = new Set();
const stats = { searches: 0, pagesRead: 0, results: 0 };

function log(phase, msg) {
  timeline.push({ phase, message: msg, time: new Date().toISOString() });
}

// ── Helper: Search SearXNG ──
async function search(query) {
  if (searched.has(query)) return [];
  searched.add(query);
  stats.searches++;
  try {
    const params = new URLSearchParams({
      q: query, format: 'json', language: 'en',
    });
    const resp = await fetch(`${SEARXNG_URL}/search?${params}`, {
      signal: AbortSignal.timeout(12000),
    });
    const data = await resp.json();
    const results = [];
    for (const r of (data.results || []).slice(0, 10)) {
      results.push({
        title: r.title || '', url: r.url || '',
        content: (r.content || '').substring(0, 500),
        engine: r.engine || '', score: r.score || 0,
        query: query,
      });
    }
    // Capture infoboxes and answers
    for (const box of (data.infoboxes || [])) {
      results.push({
        title: box.infobox || 'Infobox',
        url: (box.urls && box.urls[0]) ? box.urls[0].url : '',
        content: box.content || '', engine: 'infobox',
        score: 100, query: query,
      });
    }
    for (const ans of (data.answers || [])) {
      if (typeof ans === 'string') {
        results.push({
          title: 'Direct Answer', url: '',
          content: ans, engine: 'answer',
          score: 100, query: query,
        });
      }
    }
    stats.results += results.length;
    return results;
  } catch (err) {
    log('search_error', `Search failed: ${query} — ${err.message}`);
    return [];
  }
}

// ── Helper: Parallel search ──
async function parallelSearch(queries) {
  const results = await Promise.allSettled(queries.map(q => search(q)));
  const all = [];
  for (const r of results) {
    if (r.status === 'fulfilled') all.push(...r.value);
  }
  return all;
}

// ── Helper: Fetch page ──
async function fetchPage(url) {
  if (fetched.has(url)) return null;
  fetched.add(url);
  const skip = ['youtube.com','twitter.com','x.com','facebook.com','instagram.com','.pdf','linkedin.com','tiktok.com'];
  if (skip.some(p => url.toLowerCase().includes(p))) return null;
  try {
    const resp = await fetch(url, {
      signal: AbortSignal.timeout(10000),
      headers: { 'User-Agent': 'HyprChat-Research/2.0' },
      redirect: 'follow',
    });
    const ct = resp.headers.get('content-type') || '';
    if (!ct.includes('text') && !ct.includes('json')) return null;
    let text = await resp.text();
    // Clean HTML
    for (const tag of ['script','style','nav','header','footer','aside','noscript']) {
      text = text.replace(new RegExp(`<${tag}[^>]*>[\\s\\S]*?</${tag}>`, 'gi'), '');
    }
    text = text.replace(/<h[1-3][^>]*>(.*?)<\/h[1-3]>/gi, '\n## $1\n');
    text = text.replace(/<li[^>]*>(.*?)<\/li>/gi, '\n• $1');
    text = text.replace(/<p[^>]*>/gi, '\n');
    text = text.replace(/<br\s*\/?>/gi, '\n');
    text = text.replace(/<[^>]+>/g, ' ');
    text = text.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>');
    text = text.replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&nbsp;/g,' ');
    text = text.replace(/[ \t]+/g, ' ').replace(/\n\s*\n\s*\n+/g, '\n\n').trim();
    if (text.length < 200) return null;
    stats.pagesRead++;
    return { url, content: text.substring(0, MAX_PAGE_CHARS) };
  } catch { return null; }
}

// ── Helper: Parallel fetch ──
async function parallelFetch(urls, limit = 5) {
  const pages = [];
  for (let i = 0; i < urls.length; i += limit) {
    const batch = urls.slice(i, i + limit);
    const results = await Promise.allSettled(batch.map(u => fetchPage(u)));
    for (const r of results) {
      if (r.status === 'fulfilled' && r.value) pages.push(r.value);
    }
  }
  return pages;
}

// ── Helper: Extract entities ──
function extractEntities(text, topicWords) {
  const entities = new Set();
  // Capitalized phrases
  const caps = text.match(/\b([A-Z][a-z]+(?:\s[A-Z][a-z]+)+)\b/g) || [];
  for (const term of caps) {
    if (!topicWords.has(term.toLowerCase()) && term.length > 5) entities.add(term);
  }
  // Quoted terms
  const quoted = text.match(/"([^"]{4,40})"/g) || [];
  for (const q of quoted) {
    const term = q.replace(/"/g, '');
    if (!term.includes('<')) entities.add(term);
  }
  // Acronyms
  const skip = new Set(['THE','AND','FOR','NOT','BUT','ARE','WAS','HAS','ITS','THIS','THAT','WITH','FROM','HTML','HTTP','URL','API']);
  const acrs = text.match(/\b([A-Z]{2,6})\b/g) || [];
  for (const a of acrs) {
    if (!skip.has(a) && !topicWords.has(a.toLowerCase())) entities.add(a);
  }
  return entities;
}

// ── Helper: Rank URLs ──
function rankUrls(findings, exclude) {
  const scores = {};
  const quality = {
    'wikipedia.org':10,'arxiv.org':9,'github.com':8,'stackoverflow.com':8,
    'nature.com':9,'docs.':8,'.gov':8,'.edu':8,'reuters.com':8,
    'arstechnica.com':7,'bbc.com':7,'nytimes.com':7,
    'medium.com':5,'dev.to':6,'techcrunch.com':6,'wired.com':6,
  };
  for (const f of findings) {
    const url = f.url || '';
    if (!url || (exclude && exclude.has(url))) continue;
    let score = f.score || 0;
    for (const [domain, bonus] of Object.entries(quality)) {
      if (url.toLowerCase().includes(domain)) { score += bonus; break; }
    }
    if ((f.content || '').length > 200) score += 3;
    if ((f.content || '').length > 500) score += 2;
    const skip = ['youtube.com','twitter.com','x.com','facebook.com','.pdf','linkedin.com'];
    if (skip.some(p => url.toLowerCase().includes(p))) score -= 100;
    if (!scores[url] || score > scores[url]) scores[url] = score;
  }
  return Object.keys(scores).sort((a,b) => scores[b] - scores[a]).filter(u => scores[u] > 0);
}

// ── Helper: AI call ──
async function askAI(prompt, maxTokens = 4096) {
  try {
    const resp = await fetch(`${OLLAMA_URL}/api/generate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: RESEARCH_MODEL, prompt, stream: false,
        options: { temperature: 0.3, num_predict: maxTokens },
      }),
      signal: AbortSignal.timeout(180000),
    });
    const data = await resp.json();
    return (data.response || '').trim();
  } catch (err) {
    log('ai_error', `AI call failed: ${err.message}`);
    return '';
  }
}

const topicWords = new Set(topic.toLowerCase().split(/\s+/));

// ================================================================
// QUICK MODE
// ================================================================
if (mode === 'quick') {
  log('quick', `Quick search: ${topic}`);
  const results = await search(topic);
  return {
    json: {
      success: results.length > 0, topic, depth: 1, mode: 'quick',
      report: results.length > 0 ? results.map((r,i) => `[${i+1}] ${r.title}\n    ${r.url}\n    ${r.content}`).join('\n\n') : 'No results found.',
      sources: results.map((r,i) => ({ index: i+1, title: r.title, url: r.url })),
      source_count: results.length,
      total_searches: 1, total_fetches: 0,
      timeline, total_time_ms: Date.now() - new Date(timeline[0]?.time || Date.now()).getTime(),
    }
  };
}

// ================================================================
// COMPARE MODE
// ================================================================
if (mode === 'compare' && topicB) {
  log('compare', `Comparing: ${topic} vs ${topicB}`);

  const [resultsA, resultsB, resultsVs] = await Promise.all([
    parallelSearch([topic, `${topic} pros cons advantages`, `${topic} use cases`]),
    parallelSearch([topicB, `${topicB} pros cons advantages`, `${topicB} use cases`]),
    parallelSearch([`${topic} vs ${topicB}`, `${topicB} vs ${topic}`, `${topic} compared to ${topicB}`]),
  ]);

  const allResults = [...resultsA, ...resultsB, ...resultsVs];
  const topUrls = rankUrls(allResults, fetched);
  const pages = await parallelFetch(topUrls.slice(0, 5));

  // Build context
  const ctx = [
    `=== ${topic.toUpperCase()} ===`,
    resultsA.map((r,i) => `[${i+1}] ${r.title}: ${r.content}`).join('\n'),
    `\n=== ${topicB.toUpperCase()} ===`,
    resultsB.map((r,i) => `[${i+1}] ${r.title}: ${r.content}`).join('\n'),
    `\n=== HEAD-TO-HEAD ===`,
    resultsVs.map((r,i) => `[${i+1}] ${r.title}: ${r.content}`).join('\n'),
  ];
  if (pages.length) {
    ctx.push('\n=== FULL SOURCE CONTENT ===');
    for (const p of pages) ctx.push(`--- ${p.url} ---\n${p.content.substring(0, 2000)}`);
  }

  const report = await askAI(`Write a comprehensive comparison of ${topic} vs ${topicB}.\n\nResearch data:\n${ctx.join('\n')}\n\nWrite a balanced comparison covering: overview of each, key differences, pros/cons, best use cases, and a recommendation. Cite sources.`, 6144);

  return {
    json: {
      success: true, topic: `${topic} vs ${topicB}`, depth, mode: 'compare',
      report,
      sources: allResults.filter(r=>r.url).map((r,i)=>({index:i+1,title:r.title,url:r.url})).slice(0,20),
      source_count: new Set(allResults.map(r=>r.url).filter(Boolean)).size,
      total_searches: stats.searches, total_fetches: stats.pagesRead,
      timeline, total_time_ms: Date.now() - new Date(timeline[0]?.time || Date.now()).getTime(),
    }
  };
}

// ================================================================
// FULL RESEARCH MODE — 5 Phases
// ================================================================
log('start', `Deep Research: ${topic} (depth ${depth}, focus: ${focus || 'none'})`);

// ── PHASE 1: Discovery ──
log('phase1', 'Discovery — broad search sweep');
const discoveryQueries = [
  topic,
  `${topic} explained`,
  `${topic} overview guide`,
  `what is ${topic}`,
];
if (focus) discoveryQueries.push(`${topic} ${focus}`);

const discoveryResults = await parallelSearch(discoveryQueries);
allFindings.push(...discoveryResults);
for (const r of discoveryResults) if (r.url) allSources.push(r.url);

// Extract entities
const entityText = allFindings.map(f => `${f.title} ${f.content}`).join(' ');
keyEntities = extractEntities(entityText, topicWords);
log('phase1', `Found ${allFindings.length} results, ${keyEntities.size} entities: ${[...keyEntities].slice(0,6).join(', ')}`);

// ── PHASE 2: Deep Dive (depth >= 2) ──
if (depth >= 2) {
  log('phase2', 'Deep Dive — reading top sources + entity queries');

  // Read top pages in parallel
  const topUrls = rankUrls(allFindings, fetched);
  const pagesToRead = Math.min(2 + depth, topUrls.length);
  const pages = await parallelFetch(topUrls.slice(0, pagesToRead));
  fullPages.push(...pages);

  // Extract more entities from page content
  for (const p of pages) {
    const pe = extractEntities(p.content, topicWords);
    for (const e of pe) keyEntities.add(e);
  }

  // Entity-driven searches in parallel
  const entityQueries = [...keyEntities].slice(0, 5).map(e => `${topic} ${e}`);
  entityQueries.push(`${topic} how it works`, `${topic} examples applications`);
  const entityResults = await parallelSearch(entityQueries.slice(0, 6));
  allFindings.push(...entityResults);
  for (const r of entityResults) if (r.url) allSources.push(r.url);

  log('phase2', `${pages.length} pages read, ${entityResults.length} new findings`);
}

// ── PHASE 3: Cross-Reference (depth >= 3) ──
if (depth >= 3) {
  log('phase3', 'Cross-Reference — verification + alternative angles');

  const xrefQueries = [
    `${topic} latest news 2025`,
    `${topic} criticism problems issues`,
    `${topic} expert analysis opinion`,
    `${topic} comparison alternatives`,
  ];
  const xrefResults = await parallelSearch(xrefQueries);
  allFindings.push(...xrefResults);
  for (const r of xrefResults) if (r.url) allSources.push(r.url);

  // Read a few more key pages
  const newTop = rankUrls(allFindings, fetched);
  const newPages = await parallelFetch(newTop.slice(0, 2));
  fullPages.push(...newPages);

  log('phase3', `${xrefResults.length} cross-ref results, ${newPages.length} pages`);
}

// ── PHASE 4: Niche & Data (depth >= 4) ──
if (depth >= 4) {
  log('phase4', 'Niche Angles — statistics, case studies, trends');

  const nicheQueries = [
    `${topic} statistics data numbers`,
    `${topic} case study real world example`,
    `${topic} future predictions trends`,
    `${topic} history evolution timeline`,
    `${topic} how it works explained`,
  ];
  // Entity-combined for deeper coverage
  for (const ent of [...keyEntities].slice(0, 3)) {
    nicheQueries.push(`${topic} ${ent} details`);
  }

  const nicheResults = await parallelSearch(nicheQueries);
  allFindings.push(...nicheResults);
  for (const r of nicheResults) if (r.url) allSources.push(r.url);

  const newTop = rankUrls(allFindings, fetched);
  const newPages = await parallelFetch(newTop.slice(0, 3));
  fullPages.push(...newPages);

  log('phase4', `${nicheResults.length} niche results, ${newPages.length} pages`);
}

// ── PHASE 5: Exhaustive Sweep (depth >= 5) ──
if (depth >= 5) {
  log('phase5', 'Exhaustive Sweep — academic, community, cross-entity');

  const sweepQueries = [
    `${topic} research paper academic`,
    `${topic} technical deep dive`,
    `${topic} common misconceptions myths`,
    `${topic} beginner guide introduction`,
    `${topic} advanced techniques`,
    `${topic} community discussion reddit forum`,
  ];
  // Entity cross-product
  const entList = [...keyEntities].slice(0, 4);
  for (let i = 0; i < entList.length; i++) {
    for (let j = i + 1; j < entList.length; j++) {
      sweepQueries.push(`${entList[i]} ${entList[j]} ${topic}`);
    }
  }

  const sweepResults = await parallelSearch(sweepQueries);
  allFindings.push(...sweepResults);
  for (const r of sweepResults) if (r.url) allSources.push(r.url);

  const newTop = rankUrls(allFindings, fetched);
  const newPages = await parallelFetch(newTop.slice(0, 3));
  fullPages.push(...newPages);

  log('phase5', `${sweepResults.length} sweep results, ${newPages.length} pages`);
}

// ================================================================
// SYNTHESIZE — AI writes the report
// ================================================================
log('synthesize', 'Generating research report...');

const uniqueSources = [...new Set(allSources.filter(Boolean))];

// Build knowledge context
const ctx = [];
if (fullPages.length) {
  ctx.push('═══ FULL PAGE CONTENT (PRIMARY SOURCES) ═══\n');
  for (const p of fullPages.slice(0, 10)) {
    ctx.push(`━━━ ${p.url} ━━━\n${p.content.substring(0, 2500)}\n`);
  }
}
ctx.push('═══ SEARCH RESULTS ═══\n');
const seen = new Set();
for (const f of allFindings) {
  if (seen.has(f.url)) continue;
  seen.add(f.url);
  ctx.push(`[${seen.size}] ${f.title}\n    ${f.url}\n    ${f.content}\n`);
  if (seen.size >= 40) break;
}

const synthesizePrompt = `You are an expert research analyst. Write a comprehensive research report.\n\nTOPIC: ${topic}${focus ? `\nFOCUS: ${focus}` : ''}\n\nRESEARCH DATA:\n${ctx.join('\n')}\n\nWrite a thorough report that:\n1. Opens with an executive summary (2-3 paragraphs)\n2. Covers all major themes discovered\n3. Includes specific facts, figures, data where available\n4. Notes conflicting information or open questions\n5. References sources inline using [Source N] notation\n6. Ends with key takeaways\n\nWrite in flowing, insightful prose. Do NOT just list results.\nLength: ${depth >= 4 ? '1000-1500' : depth >= 3 ? '700-1000' : depth >= 2 ? '500-700' : '300-500'} words.`;

const report = await askAI(synthesizePrompt, depth >= 4 ? 8192 : 4096);
log('synthesize', `Report: ${report.length} chars`);

// Build source list
const sourcesFormatted = [];
const seenSrc = new Set();
for (const f of allFindings) {
  if (!f.url || seenSrc.has(f.url)) continue;
  seenSrc.add(f.url);
  sourcesFormatted.push({ index: seenSrc.size, title: f.title, url: f.url });
  if (seenSrc.size >= 25) break;
}

return {
  json: {
    success: report.length > 100,
    topic, depth, mode: 'research',
    focus: focus || null,
    report,
    sources: sourcesFormatted,
    source_count: uniqueSources.length,
    total_searches: stats.searches,
    total_fetches: stats.pagesRead,
    pages_read: fullPages.length,
    key_entities: [...keyEntities].slice(0, 15),
    queries_used: [...searched],
    timeline,
    total_time_ms: Date.now() - new Date(timeline[0]?.time || Date.now()).getTime(),
  }
};
